// Inputs (from a webhook, AI node, schedule, etc.). Defaults shown for testing.
const input = $input.first().json;
const repoFullName = input.repoFullName || 'rascal-sites/rascal-site-samikiias';
const title = input.title || 'Automaattinen kirjoitus';
const slug = (input.slug || title)
  .toLowerCase()
  .replace(/[äå]/g, 'a')
  .replace(/ö/g, 'o')
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-+|-+$/g, '');
const date = input.date || new Date().toISOString().slice(0, 10);
const body = input.body || 'Sisältö tähän.';

const markdown = `---\ntitle: ${title}\nslug: ${slug}\ndate: ${date}\npublished: true\n---\n\n${body}\n`;
const content = Buffer.from(markdown, 'utf8').toString('base64');
const path = `content/posts/${slug}.md`;

return [{
  json: {
    url: `https://api.github.com/repos/${repoFullName}/contents/${path}`,
    ghBody: { message: `content: add ${slug}`, content }
  }
}];
